#include <bits/stdc++.h>
using namespace std;
const int N=45;
int n,m;

string cheng(string x,string y)
{
    // cout<<x << "  " << y <<endl;
    string a=x,b=y;
    int a1[45],b1[45],c[45];
    memset(a1,0,sizeof(a1));
    memset(b1,0,sizeof(b1));
    memset(c,0,sizeof(c));
    reverse(a.begin(),a.end());
    reverse(b.begin(),b.end());
    for(int i=0;i<=a.size()-1;i++)
    {
        a1[i]=a[i]-48;
    }
    for(int i=0;i<=b.size()-1;i++)
    {
        b1[i]=b[i]-48;
    }
    int len1=a.size(),len2=b.size();
    for(int i=0;i<=len1-1;i++)
    {
        for(int j=0;j<=len2-1;j++)
        {
            c[i+j]=a1[i]*b1[j]+c[i+j];
            c[i+j+1]=c[i+j]/10+c[i+j+1];
            c[i+j]%=10;
        }
    }
    int len=len1+len2;
    while(c[len]==0&&len>0)
    {
        len--;
    }
    string ans;
    for(int i=len;i>=0;i--)
    {
        ans=ans+to_string(c[i]);
    }
    return ans;
}
string dp[N][N],num[N][N];
string s;
bool fun(string s1,string s2)
{
    if(s1.size()<s2.size()) return 1;
    if(s1.size()>s2.size()) return 0;
    return (s1<s2);
}
int main()
{
    cin>>n>>m>>s;
    s=" "+s;
    for(int i=1;i<=n;i++)
    {
        for(int j=i;j<=n;j++)
        {
            num[i][j]=s.substr(i,j-i+1);
            // cout<<i<<" "<<j<<" "<<num[i][j]<<"\n";
        }
    }
    for(int i=1;i<=n;i++)
    {
        dp[i][0]=num[1][i];
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=min(m,i-1);j++)
        {
            for(int k=j;k<i;k++)
            {
                string t=cheng(dp[k][j-1],num[k+1][i]);
                // cout<<k<<" "<<j-1<<" "<<dp[k][j-1]<<" "<<num[k+1][i]<<" "<<t<<"\n";
                if(fun(dp[i][j],t)) dp[i][j]=t;
                // cout<<i<<" "<<j<<" "<<dp[i][j]<<"\n";
            }
            // cout<<dp[i][j]<<"        ";
        }
        // cout<<'\n';
    }
    cout<<dp[n][m];
    return 0;
}
